args.cypher:
MATCH (sm:Submodel)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
WHERE sm.idShort = 'HierarchicalStructures' OR EXISTS {
  MATCH (sm)-[:HAS_ELEMENT]->(e:Entity)
}
RETURN sm.idShort, sm.id, sc.id

MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(asset:Asset)
WHERE aas.id IN ['urn:aas:hall4'] OR EXISTS {
  MATCH (aas2:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
  WHERE sm.id IN ['urn:submodel:crx10ia:001:nameplate', 'urn:submodel:mir100:001:nameplate', 'urn:submodel:ur3e:002:nameplate']
}
RETURN aas.idShort, aas.id, asset.globalAssetId

// Check UR3e capability description
MATCH (sm:Submodel {id: 'urn:submodel:ur3e:type:capabilitydescription'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, el.category, el.value AS value

// Discover all submodels and their semanticIds to understand the structure
MATCH (sm:Submodel)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
RETURN DISTINCT sc.id ORDER BY sc.id

// List all AAS shells and their assets to see what's available
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset)
RETURN aas.idShort AS aas_idShort, aas.id AS aas_id, a.globalAssetId AS asset_id, a.assetKind AS asset_kind

// Explore HierarchicalStructures submodel of Hall4
MATCH (sm:Submodel {id: 'urn:submodel:hall4:hierarchicalstructures'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN labels(el) AS element_types, el.idShort AS element_idShort, el.category AS category

// Get the full path from EntryNode to asset, with entity properties
MATCH (sm:Submodel {id: 'urn:submodel:hall4:hierarchicalstructures'})-[:HAS_ELEMENT*]->(entry:Entity {idShort: 'EntryNode'})-[:HAS_ELEMENT*]->(child:Entity)-[:REPRESENTS_ASSET]->(asset:Asset)
RETURN child.idShort AS device, asset.globalAssetId AS assetId, child.entityType AS entityType
